list.value:
cat > /tmp/krb5_new.conf << 'KRB5EOF' [libdefaults] default_realm = KING.HTB dns_lookup_realm = false dns_lookup_kdc = false ticket_lifetime = 24h forwardable = true udp_preference_limit = 0 default_tgs_enctypes = aes256-cts-hmac-sha1-96 aes128-cts-hmac-sha1-96 rc4-hmac default_tkt_enctypes = aes256-cts-hmac-sha1-96 aes128-cts-hmac-sha1-96 rc4-hmac
[realms] KING.HTB = { kdc = 172.16.1.1 admin_server = 172.16.1.1 default_domain = king.htb }
[domain_realm] .king.htb = KING.HTB king.htb = KING.HTB mq = KING.HTB .mq = KING.HTB KRB5EOF
export KRB5CCNAME=/tmp/krb5cc_1600801117_Qxs0zd; export KRB5_CONFIG=/tmp/krb5_new.conf;
LDAP1=$(timeout 15 ldapsearch -H ldap://172.16.1.1 -Y GSSAPI -b "DC=king,DC=htb" "(objectClass=user)" sAMAccountName 2>&1 | head -50); LDAP2=$(timeout 15 ldapsearch -H ldap://openAD.king.htb -Y GSSAPI -b "DC=king,DC=htb" "(objectClass=user)" sAMAccountName 2>&1 | head -30); echo "=LDAP1=$LDAP1=LDAP2=$LDAP2"
